script:
frappe.ui.form.on('Case', {
    refresh: function(frm) {
        // 2. HOURLY: Add Button (Since it's not in the DocType)
        if (frm.doc.billing_type === 'Hourly' && frm.doc.status === 'Active') {
            frm.add_custom_button(__('Create Invoice'), function() {
                frm.trigger('create_hourly_invoice');
            });
        }
    },
    // --- BUTTON 3: HOURLY (Custom Event) ---
    create_hourly_invoice: function(frm) {
        frappe.call({
            method: 'create_hourly_invoice',
            doc: frm.doc,
            freeze: true,
            callback: function(r) {
                if (!r.exc) {
                    frm.reload_doc();
                }
            }
        });
    }
});

frappe.ui.form.on('Timesheet Detail', {
    custom_case: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.custom_case) {
            frappe.call({
                method: 'law_management.law_management.doctype.case.case.get_member_rate',
                args: {
                    case: row.custom_case,
                    user: frappe.session.user
                },
                callback: function(r) {
                    if (r.message) {
                        frappe.model.set_value(cdt, cdn, 'billing_rate', r.message);
                        frappe.msgprint(`Rate updated to ${r.message} based on Case Agreement.`);
                    }
                }
            });
        }
    }
});

frappe.ui.form.on('Task', {
    refresh: function(frm) {
        // Apply filter directly to the 'assignees' field
        frm.set_query('assignees', function() {
            return {
                query: 'law_management.law_management.doctype.case.case.get_member_query',
                filters: {
                    case_name: frm.doc.custom_case
                }
            };
        });
    },
    custom_case: function(frm) {
        frm.set_value('assignees', []);
    }
});
